import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        line = data[i] if i < len(data) else ''
        out.append(str(line.count('cat')))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

